Context.isEnabled:
var amo = Services.getValue(AmountOrdered.dataBinding);	
var costType = Services.getValue(CostType.dataBinding);
if (('A' == costType || 'M' == costType) && !( null != amo && amo > 0 )) {
	return false; }
else {
	var hco = Services.getValue(HasCostOrder.dataBinding);
	var cam = Services.getValue(CostAmount.dataBinding);
	return(  ('Y'  == hco  ||  (null != cam && cam > 0) || ( null != amo && amo > 0 ))  ); }

Context.validate:
var checkDate = Services.getValue(PaymentDate.dataBinding);
var err = null;
if (false == isFutureDate(checkDate)) {
	err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInThePast_Msg"); }
return err;

var checkDate = Services.getValue(PaymentDate.dataBinding);
var isValid = isFutureDate(checkDate);
var err = null;
if( false != isValid)
{	
	if(isNonWorkingDate( checkDate ))
	{	err = ErrorCode.getErrorCode("CaseMan_dateNonWorkingDay_Msg");
	}
}
else
{ 	err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInThePast_Msg");
}
return err;

